import{_ as e,a as t,b as r,c as d}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as c,o as n,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Redundant Backup နှင့် Read Source Switching","description":"","frontmatter":{},"headers":[],"relativePath":"my/Other/redundant-backup-and-read-source.md","filePath":"my/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),p={name:"my/Other/redundant-backup-and-read-source.md"};function u(s,a,h,o,b,k){return n(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="redundant-backup-နှင့်-read-source-switching" tabindex="-1">Redundant Backup နှင့် Read Source Switching <a class="header-anchor" href="#redundant-backup-နှင့်-read-source-switching" aria-label="Permalink to &quot;Redundant Backup နှင့် Read Source Switching&quot;">​</a></h1><p>Redundant backup က uploaded file တစ်ခုရဲ့ extra copy ကိုသိမ်းပေးပါတယ်။</p><p>primary file နဲ့ backup file နှစ်ခုလုံးကို read sources အဖြစ်သုံးနိုင်ပါတယ်။ visitors တွေအနေနဲ့ များသောအားဖြင့်ကွာခြားမှုမမြင်ရပါ။ ကွာခြားတာက file ကို ဘယ် storage channel က serve လုပ်နေလဲဆိုတာပဲဖြစ်ပါတယ်။</p><h2 id="redundant-backup-က-ဘာလုပ်နိုင်လဲ" tabindex="-1">Redundant Backup က ဘာလုပ်နိုင်လဲ <a class="header-anchor" href="#redundant-backup-က-ဘာလုပ်နိုင်လဲ" aria-label="Permalink to &quot;Redundant Backup က ဘာလုပ်နိုင်လဲ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>extra copy သိမ်းခြင်း</td><td>single channel failure risk လျှော့ရန် files ကိုအခြား upload channel ထဲ backup လုပ်သည်။</td></tr><tr><td>read source switch</td><td>backup အောင်မြင်ပြီးနောက် file reads ကို primary channel နဲ့ backup channel ကြား switch လုပ်သည်။</td></tr><tr><td>single-file backup</td><td>file details page မှ file တစ်ခု backup လုပ်သည်။</td></tr><tr><td>batch backup</td><td>admin page မှ files အများအပြား select လုပ်ပြီးအတူ backup လုပ်သည်။</td></tr><tr><td>global redundant backup</td><td>Other Settings မှ folder အလိုက် files backup လုပ်သည်။</td></tr></tbody></table><h2 id="redundant-backup-entry" tabindex="-1">Redundant Backup Entry <a class="header-anchor" href="#redundant-backup-entry" aria-label="Permalink to &quot;Redundant Backup Entry&quot;">​</a></h2><p>ဖွင့်ပါ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Redundant Backup</span></span></code></pre></div><p><img src="'+e+'" alt="Redundant backup" loading="lazy"></p><p>ဒီ entry က folder တစ်ခုသို့မဟုတ် files အားလုံးအတွက် bulk backups ထည့်ရန်သင့်တော်ပါတယ်။</p><p>backup channel ကို manually ရွေးနိုင်သလို automatic switching ကိုရွေးပြီး ImgBed ကို suitable backup channel ရှာခိုင်းနိုင်ပါတယ်။</p><h2 id="file-details-မှ-backup" tabindex="-1">File Details မှ Backup <a class="header-anchor" href="#file-details-မှ-backup" aria-label="Permalink to &quot;File Details မှ Backup&quot;">​</a></h2><p>admin panel ထဲက file details page ကိုဖွင့်ပြီး backup ကိုနှိပ်ပါ။</p><p><img src="'+t+'" alt="Backup in file details" loading="lazy"></p><p>အရေးကြီး file တစ်ခုကိုလိုအပ်တဲ့အခါ backup လုပ်ရန်ဒီနည်းကသင့်တော်ပါတယ်။</p><p>backup အောင်မြင်ပြီးနောက် file details page မှာ available read sources တွေပြပါမယ်။</p><h2 id="selection-ဖြင့်-batch-backup" tabindex="-1">Selection ဖြင့် Batch Backup <a class="header-anchor" href="#selection-ဖြင့်-batch-backup" aria-label="Permalink to &quot;Selection ဖြင့် Batch Backup&quot;">​</a></h2><p>admin panel မှာ files အများအပြား select လုပ်ပြီး batch backup run လုပ်ပါ။</p><p><img src="'+r+'" alt="Batch backup" loading="lazy"></p><p>files အုပ်စုတစ်ခု process လုပ်ရန်သင့်တော်ပါတယ်။</p><p>Selection backup, file details backup, Other Settings အောက်က redundant backup အားလုံးက backup system တစ်ခုတည်းကိုသုံးပါတယ်။ entry points ပဲကွာပါတယ်။</p><h2 id="backup-ပြီးနောက်-read-source-switch-လုပ်ခြင်း" tabindex="-1">Backup ပြီးနောက် Read Source Switch လုပ်ခြင်း <a class="header-anchor" href="#backup-ပြီးနောက်-read-source-switch-လုပ်ခြင်း" aria-label="Permalink to &quot;Backup ပြီးနောက် Read Source Switch လုပ်ခြင်း&quot;">​</a></h2><p>backup complete ဖြစ်ပြီးနောက် file details page က read source switch လုပ်ခွင့်ပေးပါတယ်:</p><table tabindex="0"><thead><tr><th>Read Source</th><th>Description</th></tr></thead><tbody><tr><td>Primary channel</td><td>original upload channel မှ read လုပ်သည်။</td></tr><tr><td>Backup channel</td><td>backup channel မှ read လုပ်သည်။</td></tr></tbody></table><p><img src="'+d+'" alt="Switch read source after backup" loading="lazy"></p><p>file က primary channel မှ serve ဖြစ်နေလား backup channel မှ serve ဖြစ်နေလား visitors တွေသိဖို့မလိုပါ။</p><p>သင်ရွေးထားတဲ့ read source က နောက်ပိုင်း file access အတွက် preferred source ဖြစ်ပါမယ်။</p><h2 id="backup-skip-ဖြစ်တဲ့အချိန်" tabindex="-1">Backup Skip ဖြစ်တဲ့အချိန် <a class="header-anchor" href="#backup-skip-ဖြစ်တဲ့အချိန်" aria-label="Permalink to &quot;Backup Skip ဖြစ်တဲ့အချိန်&quot;">​</a></h2><p>backup အချိန်မှာ အောက်ပါ cases တွေ skip ဖြစ်ပါမယ်။ ဒါတွေက errors မဟုတ်ပါ။</p><table tabindex="0"><thead><tr><th>Case</th><th>Why It Is Skipped</th></tr></thead><tbody><tr><td>Already backed up</td><td>backup ရှိပြီးသား file ကိုပြန် backup မလုပ်ပါ။</td></tr><tr><td>Primary and backup channels are the same</td><td>backup အဓိပ္ပါယ်ရှိဖို့ copy ကိုအခြား channel ထဲသိမ်းရပါမယ်။</td></tr><tr><td>No usable backup channel</td><td>သင့်တော်တဲ့ alternative channel မရှိပါ။</td></tr></tbody></table><p>အတိုချုပ်: backups တွေက အခြား channel ထဲသွားရပြီး already backed-up files တွေက extra space ထပ်မသုံးပါ။</p><h2 id="primary-channel-vs-backup-channel" tabindex="-1">Primary Channel vs Backup Channel <a class="header-anchor" href="#primary-channel-vs-backup-channel" aria-label="Permalink to &quot;Primary Channel vs Backup Channel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td>Primary channel</td><td>file ကိုပထမဆုံး upload လုပ်ရာ channel။</td></tr><tr><td>Backup channel</td><td>redundant copy သိမ်းထားတဲ့ channel။</td></tr><tr><td>Primary read source</td><td>file ကို လက်ရှိ primary channel မှ read လုပ်နေသည်။</td></tr><tr><td>Backup read source</td><td>file ကို လက်ရှိ backup channel မှ read လုပ်နေသည်။</td></tr></tbody></table><p>Primary နဲ့ backup read sources တွေက user-facing behavior တူညီပါတယ်။</p><p>backup file available ဖြစ်နေသရွေ့ backup read source ကို switch လုပ်ပြီးနောက် images, videos, download links တွေ ဆက်အလုပ်လုပ်ပါမယ်။</p><h2 id="file-delete-လုပ်တဲ့အခါ-ဘာဖြစ်မလဲ" tabindex="-1">File Delete လုပ်တဲ့အခါ ဘာဖြစ်မလဲ <a class="header-anchor" href="#file-delete-လုပ်တဲ့အခါ-ဘာဖြစ်မလဲ" aria-label="Permalink to &quot;File Delete လုပ်တဲ့အခါ ဘာဖြစ်မလဲ&quot;">​</a></h2><p>file delete လုပ်တဲ့အခါ ImgBed က primary file နဲ့ backup file နှစ်ခုလုံးကို delete လုပ်ပါမယ်။</p>',37)])])}const g=c(p,[["render",u]]);export{y as __pageData,g as default};
